import json
import pandas as pd
import numpy as np
import pyarrow as pa
import pyarrow.parquet as pq

# Load source A
with open('/data/source_a/users.json', 'r') as f:
    source_a = json.load(f)

# Load source B
source_b = pd.read_csv('/data/source_b/users.csv').replace({np.nan: None}).to_dict('records')

# Load source C
source_c = pd.read_parquet('/data/source_c/users.parquet').replace({np.nan: None}).to_dict('records')

def normalize(record, source_name):
    normalized = {}

    # user_id
    if 'id' in record and record['id'] is not None: normalized['user_id'] = int(record['id'])
    elif 'user_id' in record and record['user_id'] is not None: normalized['user_id'] = int(record['user_id'])
    elif 'userId' in record and record['userId'] is not None: normalized['user_id'] = int(record['userId'])

    # name
    if 'full_name' in record and record['full_name'] is not None: normalized['name'] = str(record['full_name'])
    elif 'name' in record and record['name'] is not None: normalized['name'] = str(record['name'])
    elif 'userName' in record and record['userName'] is not None: normalized['name'] = str(record['userName'])

    # email
    if 'email' in record and record['email'] is not None: normalized['email'] = str(record['email'])
    elif 'email_address' in record and record['email_address'] is not None: normalized['email'] = str(record['email_address'])

    # created_date
    if 'registration_date' in record and record['registration_date'] is not None: normalized['created_date'] = str(record['registration_date'])
    elif 'created_at' in record and record['created_at'] is not None: normalized['created_date'] = str(record['created_at'])
    elif 'joined' in record and record['joined'] is not None: normalized['created_date'] = str(record['joined'])

    # status
    if 'status' in record and record['status'] is not None:
        normalized['status'] = str(record['status'])

    return normalized

norm_a = {r['user_id']: r for r in [normalize(r, 'source_a') for r in source_a]}
norm_b = {r['user_id']: r for r in [normalize(r, 'source_b') for r in source_b]}
norm_c = {r['user_id']: r for r in [normalize(r, 'source_c') for r in source_c]}

all_users = set(norm_a.keys()) | set(norm_b.keys()) | set(norm_c.keys())

conflicts = []
merged = []

for uid in sorted(all_users):
    sources = {}
    if uid in norm_a: sources['source_a'] = norm_a[uid]
    if uid in norm_b: sources['source_b'] = norm_b[uid]
    if uid in norm_c: sources['source_c'] = norm_c[uid]

    fields = ['name', 'email', 'created_date', 'status']

    final_record = {'user_id': uid}

    for field in fields:
        field_vals = {}
        for src_name in ['source_a', 'source_b', 'source_c']:
            if src_name in sources and field in sources[src_name]:
                field_vals[src_name] = sources[src_name][field]

        if not field_vals:
            continue

        unique_vals = set(field_vals.values())

        selected_val = None
        for src in ['source_a', 'source_b', 'source_c']:
            if src in field_vals:
                selected_val = field_vals[src]
                break

        final_record[field] = selected_val

        if len(unique_vals) > 1:
            conflicts.append({
                "user_id": uid,
                "field": field,
                "values": field_vals,
                "selected": selected_val
            })

    merged.append(final_record)

with open('/app/conflicts.json', 'w') as f:
    json.dump({
        "total_conflicts": len(conflicts),
        "conflicts": conflicts
    }, f, indent=2)

df = pd.DataFrame(merged)

# Ensure columns: user_id (int), name (str), email (str), created_date (str), status (str)
for col in ['name', 'email', 'created_date', 'status']:
    if col not in df.columns:
        df[col] = None

# Reorder columns to match
df = df[['user_id', 'name', 'email', 'created_date', 'status']]

schema = pa.schema([
    ('user_id', pa.int64()),
    ('name', pa.string()),
    ('email', pa.string()),
    ('created_date', pa.string()),
    ('status', pa.string())
])

table = pa.Table.from_pandas(df, schema=schema)
pq.write_table(table, '/app/merged_users.parquet')
